<template>
    <div class="personal-wrapper">
        <div class="personal-body">
            <div class="title">编辑个人信息</div>
            <a-form :model="store.state.userInfo" :rules="rules" ref="infoForm" :label-col="labelCol" :wrapper-col="wrapperCol" class="infoForm">
                <a-form-item label=" 用户头像" name="avatar">
                    <a-upload class="avatar-uploader" :action="uploadUrl" :data="uploadData" accept="image/jpeg" :headers="uploadHeaders" :showUploadList="false" @change="handleChange" :beforeUpload="beforeAvatarUpload">
                        <img v-if="avatarUrl" :src="avatarUrl" class="avatar">
                        <span v-if="loading">上传中
                            <loading-outlined />
                        </span>
                    </a-upload>
                </a-form-item>
                <a-form-item label="账户名称" name="name">
                    <a-input v-model:value="store.state.userInfo.name"></a-input>
                </a-form-item>
                <a-form-item label="昵称" name="nickname">
                    <a-input v-model:value="store.state.userInfo.nickname"></a-input>
                </a-form-item>
                <a-form-item label="年龄" name="age">
                    <a-input-number v-model:value="store.state.userInfo.age" :min="1" :max="99"></a-input-number>
                </a-form-item>
                <a-form-item label="邮件地址" name="email">
                    <a-input v-model:value="store.state.userInfo.email"></a-input>
                </a-form-item>
                <a-form-item style="margin-bottom:0">
                    <a-button type="primary" @click="submitForm" shape="round">保存</a-button>
                </a-form-item>
            </a-form>
        </div>
    </div>
</template>
<script>
import { inject, ref, reactive, onMounted } from "vue";
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import { message } from "ant-design-vue";
import { LoadingOutlined } from "@ant-design/icons-vue";

export default {
    components: {
        LoadingOutlined
    },
    setup() {
        const router = useRouter();
        const store = useStore();
        const $api = inject("$api");

        const rules = reactive({
            name: [
                {
                    type: "string",
                    required: true,
                    message: "请输入账户名称",
                    trigger: "blur"
                },
                {
                    type: "string",
                    min: 3,
                    max: 5,
                    message: "长度在 3 到 5 个字符",
                    trigger: "blur"
                }
            ],
            nickname: [
                {
                    required: true,
                    message: "请输入昵称",
                    trigger: "blur",
                    type: "string"
                }
            ],
            age: [{ required: true, type: "number", message: "请输入年龄" }],
            email: [
                { required: true, type: "email", message: "请输入邮件地址" }
            ]
        });

        const infoForm = ref(null);
        let loading = ref(false);
        let avatarUrl = ref(store.state.userInfo.avatar);
        const labelCol = reactive({ span: 2 });
        const wrapperCol = reactive({ span: 14 });
        const uploadData = reactive({ cloudPath: "avatar/" });
        const uploadUrl = ref(
            `${process.env.VUE_APP_SERVER_URL}/api/common/uploadImage`
        );
        const uploadHeaders = reactive({
            Authorization: ""
        });

        const submitForm = () => {
            infoForm.value.validate().then(() => {
                updateUserInfo();
            });
        };

        const updateUserInfo = () => {
            store.commit("updateUserInfo", {
                key: "avatar",
                value: avatarUrl
            });
            $api.user.updateUserInfo(store.state.userInfo).then(() => {
                router.push({ path: "/home" });
                message.success("更新成功");
            });
        };

        const beforeAvatarUpload = (file) => {
            uploadHeaders.Authorization = localStorage.getItem("token");
            const isJPG = file.type === "image/jpeg";
            const isLt2M = file.size / 1024 / 1024 < 2;

            if (!isJPG) {
                message.error("上传头像图片只能是 JPG 格式!");
            }
            if (!isLt2M) {
                message.error("上传头像图片大小不能超过 2MB!");
            }
            return isJPG && isLt2M;
        };

        const handleChange = (info) => {
            if (info.file.status === "uploading") {
                loading.value = true;
                return;
            }
            if (info.file.status === "done") {
                loading.value = false;
                avatarUrl = info.file.response.data.tempFileURL;
                store.dispatch("getUserInfo");
            }
            if (info.file.status === "error") {
                loading.value = false;
            }
        };

        onMounted(() => {
            store.dispatch("getUserInfo");
        });

        return {
            labelCol,
            wrapperCol,
            uploadUrl,
            uploadHeaders,
            uploadData,
            loading,
            store,
            rules,
            avatarUrl,
            submitForm,
            updateUserInfo,
            infoForm,
            beforeAvatarUpload,
            handleChange
        };
    }
};
</script>

<style lang="scss">
.personal-wrapper {
    width: 100%;
    height: 100%;

    .personal-body {
        display: flex;
        flex-direction: column;
        padding: 16px;
        width: 1136px;
        margin: 16px auto;
        box-shadow: 0 1px 8px 0 rgba(0, 0, 0, 0.1);
        min-height: calc(100% - 32px);

        .title {
            margin-bottom: 16px;
            font-weight: bold;
        }

        .infoForm {
            .ant-form-item-label {
                text-align: left;
            }
            .avatar-uploader .a-upload {
                border: 1px dashed #000;
                border-radius: 6px;
                cursor: pointer;
                position: relative;
                overflow: hidden;
            }
            .avatar-uploader .a-upload:hover {
                border-color: #409eff;
            }
            .avatar-uploader-icon {
                font-size: 28px;
                color: #8c939d;
                width: 128px;
                height: 128px;
                line-height: 128px;
                text-align: center;
            }
            .avatar {
                width: 128px;
                height: 128px;
                display: block;
            }
            .a-form-item__label {
                text-align: left;
            }
        }
    }
}
</style>
